//! Spec-compliance tests: Stories — Headers, Footers, Footnotes, Endnotes
//! (ISO 29500-1 §17.10, §17.11)
//!
//! These tests verify our implementation against specific OOXML story
//! constructs. Tests marked `#[ignore]` document known gaps.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{BlockNode, CanonDoc, HeaderFooterKind, InlineNode, Mark, NoteType, OpaqueKind};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/stories";

// ── helpers ──────────────────────────────────────────────────────────────
/// Extract plain text from blocks.
fn blocks_text(blocks: &[stemma::TrackedBlock]) -> String {
    let mut text = String::new();
    for tb in blocks {
        if let BlockNode::Paragraph(p) = &tb.block {
            for inline in p.all_inlines() {
                if let InlineNode::Text(t) = inline {
                    text.push_str(&t.text);
                }
            }
        }
    }
    text
}

/// Check if blocks contain a text node with the Bold mark.
fn blocks_have_bold(blocks: &[stemma::TrackedBlock]) -> bool {
    blocks.iter().any(|tb| {
        if let BlockNode::Paragraph(p) = &tb.block {
            p.all_inlines().any(|inline| {
                if let InlineNode::Text(t) = inline {
                    t.marks.contains(&Mark::Bold)
                } else {
                    false
                }
            })
        } else {
            false
        }
    })
}

/// Find a FootnoteReference opaque in body blocks, return its reference_id.
fn find_footnote_ref_in_body(doc: &CanonDoc) -> Option<String> {
    for tb in &doc.blocks {
        if let BlockNode::Paragraph(p) = &tb.block {
            for inline in p.all_inlines() {
                if let InlineNode::OpaqueInline(oi) = inline
                    && let OpaqueKind::FootnoteReference(ref_data) = &oi.kind
                {
                    return Some(ref_data.reference_id.clone());
                }
            }
        }
    }
    None
}

/// Find an EndnoteReference opaque in body blocks, return its reference_id.
fn find_endnote_ref_in_body(doc: &CanonDoc) -> Option<String> {
    for tb in &doc.blocks {
        if let BlockNode::Paragraph(p) = &tb.block {
            for inline in p.all_inlines() {
                if let InlineNode::OpaqueInline(oi) = inline
                    && let OpaqueKind::EndnoteReference(ref_data) = &oi.kind
                {
                    return Some(ref_data.reference_id.clone());
                }
            }
        }
    }
    None
}

// ── Header types (§17.10.5) ─────────────────────────────────────────────

/// ISO 29500-1 §17.10.5: Three header types — default, first page, even page.
/// Verify that all three HeaderStory entries are parsed with correct kinds.
#[test]
fn spec_header_types_count() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "header-types");
    assert_eq!(
        doc.headers.len(),
        3,
        "should have 3 headers (default, first, even)"
    );
}

/// Verify header kinds are correctly assigned from w:type attribute.
#[test]
fn spec_header_types_kinds() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "header-types");
    let kinds: Vec<&HeaderFooterKind> = doc.headers.iter().map(|h| &h.kind).collect();
    assert!(
        kinds.contains(&&HeaderFooterKind::Default),
        "should have Default header, got kinds: {kinds:?}"
    );
    assert!(
        kinds.contains(&&HeaderFooterKind::First),
        "should have First header, got kinds: {kinds:?}"
    );
    assert!(
        kinds.contains(&&HeaderFooterKind::Even),
        "should have Even header, got kinds: {kinds:?}"
    );
}

/// Verify each header has content matching its type.
#[test]
fn spec_header_types_content() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "header-types");

    let default_hdr = doc
        .headers
        .iter()
        .find(|h| h.kind == HeaderFooterKind::Default)
        .expect("should have Default header");
    let text = blocks_text(&default_hdr.blocks);
    assert!(
        text.contains("Default Header"),
        "Default header text should contain 'Default Header', got: '{text}'"
    );

    let first_hdr = doc
        .headers
        .iter()
        .find(|h| h.kind == HeaderFooterKind::First)
        .expect("should have First header");
    let text = blocks_text(&first_hdr.blocks);
    assert!(
        text.contains("First Page Header"),
        "First header text should contain 'First Page Header', got: '{text}'"
    );

    let even_hdr = doc
        .headers
        .iter()
        .find(|h| h.kind == HeaderFooterKind::Even)
        .expect("should have Even header");
    let text = blocks_text(&even_hdr.blocks);
    assert!(
        text.contains("Even Page Header"),
        "Even header text should contain 'Even Page Header', got: '{text}'"
    );
}

