// ── Footnote references (§17.11.13) ─────────────────────────────────────

/// ISO 29500-1 §17.11.13: Body contains footnoteReference linking to
/// FootnoteStory by ID.
#[test]
fn spec_footnote_reference_in_body() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "footnote-references");
    let ref_id = find_footnote_ref_in_body(&doc);
    assert_eq!(
        ref_id.as_deref(),
        Some("1"),
        "body should contain footnoteReference with id=1"
    );
}

/// Footnote story with id=1 should exist and be Normal type.
#[test]
fn spec_footnote_reference_story_exists() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "footnote-references");
    let normal_notes: Vec<_> = doc
        .footnotes
        .iter()
        .filter(|fn_| fn_.note_type == NoteType::Normal)
        .collect();
    assert!(
        !normal_notes.is_empty(),
        "should have at least one Normal footnote"
    );
    let fn1 = normal_notes.iter().find(|fn_| fn_.id == "1");
    assert!(
        fn1.is_some(),
        "should have FootnoteStory with id=1, got ids: {:?}",
        normal_notes.iter().map(|n| &n.id).collect::<Vec<_>>()
    );
}

/// Footnote content should be parsed.
#[test]
fn spec_footnote_reference_content() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "footnote-references");
    let fn1 = doc
        .footnotes
        .iter()
        .find(|fn_| fn_.id == "1")
        .expect("should have footnote id=1");
    let text = blocks_text(&fn1.blocks);
    assert!(
        text.contains("This is footnote one"),
        "footnote 1 text should contain 'This is footnote one', got: '{text}'"
    );
}

