// ── Footnote/endnote types (§17.11.20) ──────────────────────────────────

/// ISO 29500-1 §17.11.20: Footnote types — separator, continuationSeparator, normal.
#[test]
fn spec_footnote_types_all_present() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "footnote-types");
    assert!(
        doc.footnotes.len() >= 3,
        "should have at least 3 footnotes, got {}",
        doc.footnotes.len()
    );

    let separator = doc
        .footnotes
        .iter()
        .find(|fn_| fn_.note_type == NoteType::Separator);
    assert!(separator.is_some(), "should have Separator footnote");

    let cont_sep = doc
        .footnotes
        .iter()
        .find(|fn_| fn_.note_type == NoteType::ContinuationSeparator);
    assert!(
        cont_sep.is_some(),
        "should have ContinuationSeparator footnote"
    );

    let normal = doc
        .footnotes
        .iter()
        .find(|fn_| fn_.note_type == NoteType::Normal);
    assert!(normal.is_some(), "should have Normal footnote");
}

/// Normal footnote should have content.
#[test]
fn spec_footnote_types_normal_has_content() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "footnote-types");
    let normal = doc
        .footnotes
        .iter()
        .find(|fn_| fn_.note_type == NoteType::Normal)
        .expect("should have Normal footnote");
    let text = blocks_text(&normal.blocks);
    assert!(
        text.contains("Normal footnote content"),
        "Normal footnote text should contain 'Normal footnote content', got: '{text}'"
    );
}

// ── Multiple sections with headers (§17.10.5) ──────────────────────────

/// ISO 29500-1 §17.10.5: Three sections, each with a different header.
/// All three should be parsed.
#[test]
fn spec_multi_section_headers_count() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "multi-section-headers");
    assert!(
        doc.headers.len() >= 3,
        "should have at least 3 headers (one per section), got {}",
        doc.headers.len()
    );
}

/// Each header should have distinct content.
#[test]
fn spec_multi_section_headers_distinct_content() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "multi-section-headers");
    let texts: Vec<String> = doc.headers.iter().map(|h| blocks_text(&h.blocks)).collect();
    assert!(
        texts.iter().any(|t| t.contains("Section 1")),
        "should have header for Section 1, got: {texts:?}"
    );
    assert!(
        texts.iter().any(|t| t.contains("Section 2")),
        "should have header for Section 2, got: {texts:?}"
    );
    assert!(
        texts.iter().any(|t| t.contains("Section 3")),
        "should have header for Section 3, got: {texts:?}"
    );
}

